    lea     ($0638,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _L_z02_UpdateMode0Demo_Sub2_LoopNameByte
    addq.b  #1,($0012,A4)
    moveq   #0,D0
    move.b  D0,($0011,A4)
    move.b  D0,($0013,A4)
    rts

