InitDemoSubphaseTransferTitlePalette:
    moveq   #35,D2
    move.b  D2,($0300,A4)
    move.b  D2,($0301,A4)
    even
_L_z02_InitDemoSubphaseTransferTitlePalette_CopyTitlePalette:
    lea     (TitlePaletteTransferRecord).l,A0
    move.b  (A0,D2.W),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D2.W)
    subq.b  #1,D2
    bpl  _L_z02_InitDemoSubphaseTransferTitlePalette_CopyTitlePalette
    moveq   #10,D2
    moveq   #0,D0
    move.b  D0,($042E,A4)
    move.b  D0,($042F,A4)
    even
_L_z02_InitDemoSubphaseTransferTitlePalette_ClearVars:
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0437,A4),A0
    move.b  D0,(A0,D2.W)
    subq.b  #1,D2
    bpl  _L_z02_InitDemoSubphaseTransferTitlePalette_ClearVars
    moveq   #10,D2
    even
_L_z02_InitDemoSubphaseTransferTitlePalette_DisableObjects:
    move.b  #$FF,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    subq.b  #1,D2
    bne  _L_z02_InitDemoSubphaseTransferTitlePalette_DisableObjects
    jmp     IncSubphase

    even
InitDemoSubphasePlayTitleSong:
    move.b  #$80,D0
    move.b  D0,($0600,A4)
    ; Select transfer buffer 8 (offset $10 in table):
    ; title nametables and attributes.
    moveq   #16,D0
    jmp     EndInitDemo

    even
StoryPaletteTransferRecord:
    ; Full 32-byte NES palette record (BG 0-3 + spr 0-3).
    ; Sprite pals 0,2 both map to CRAM pal 2; 1,3 both map to CRAM pal 3.
    ; Sequential processing: last write wins â spr pal 2-3 are the final values.
    dc.b    $3F, $00, $20, $0F, $30, $30, $30, $0F
    dc.b    $21, $30, $30, $0F, $16, $30, $30, $0F
    dc.b    $29, $1A, $09, $0F, $29, $37, $17, $0F
    dc.b    $02, $22, $30, $0F, $16, $27, $30, $0F
    dc.b    $0B, $1B, $2B, $FF

    even
InitDemoSubphaseTransferStoryPalette:
    moveq   #35,D2
    move.b  D2,($0300,A4)
    move.b  D2,($0301,A4)
    even
_L_z02_InitDemoSubphaseTransferStoryPalette_CopyStoryPalette:
    lea     (StoryPaletteTransferRecord).l,A0
    move.b  (A0,D2.W),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D2.W)
    subq.b  #1,D2
    bpl  _L_z02_InitDemoSubphaseTransferStoryPalette_CopyStoryPalette
    moveq   #10,D2
    moveq   #0,D0
    even
_L_z02_InitDemoSubphaseTransferStoryPalette_ClearVars:
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0437,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0444,A4),A0
    move.b  D0,(A0,D2.W)
    subq.b  #1,D2
    bpl  _L_z02_InitDemoSubphaseTransferStoryPalette_ClearVars
    jmp     IncSubphase

    even
InitDemoSubphaseTransferStoryTiles:
    ; PATCHED (P10): Clear both nametables (V64 plane) at story scroll init
    move.b  #$20,D0
    move.b  #$24,D2
    moveq   #0,D3
    jsr     _clear_nametable_fast
    move.b  #$28,D0
    jsr     _clear_nametable_fast
    addq.b  #1,($005C,A4)
    moveq   #16,D0
    move.b  D0,($00FC,A4)
    ; Select transfer buffer 1 (offset 2 in table):
    ; Story nametables and attributes.
    moveq   #2,D0
    even
EndInitDemo:
    move.b  D0,($0014,A4)
    moveq   #0,D0
    move.b  D0,($042D,A4)
    addq.b  #1,($0011,A4)
    rts

    even
AnimateDemoPhase0Subphase0:
    ; Animate while we wait about 512 frames.
    ;
    move.b  ($0015,A4),D0
    andi.b #$01,D0
    beq  _L_z02_AnimateDemoPhase0Subphase0_SkipTimer
    addq.b  #1,($041A,A4)
    move.b  ($041A,A4),D0
    bne  _L_z02_AnimateDemoPhase0Subphase0_SkipTimer
    jmp     IncSubphase

    even
_L_z02_AnimateDemoPhase0Subphase0_SkipTimer:
    jsr     AnimateDemoPhase0Subphase0Artifacts
    rts

    even
AnimateDemoPhase1Subphase0:
    move.b  ($0015,A4),D0
    andi.b #$01,D0
    beq  _L_z02_AnimateDemoPhase1Subphase0_CheckVScroll
    addq.b  #1,($00FC,A4)
    move.b  ($00FC,A4),D0
    cmpi.b  #$F0,D0
    bne  _L_z02_AnimateDemoPhase1Subphase0_CheckVScroll
    addq.b  #1,($0415,A4)
    ; The bottom of NT 2 is also the top of NT 0.
    ; So, reset CurVScroll and the base NT.
    moveq   #0,D0
    move.b  D0,($00FC,A4)
    addq.b  #1,($005C,A4)
    even
_L_z02_AnimateDemoPhase1Subphase0_CheckVScroll:
    ; Scrolling hasn't ended until we've scrolled to the bottom,
    ; wrapped around, and scrolled 8 more lines.
    move.b  ($00FC,A4),D0
    cmpi.b  #$08,D0
    bne  _L_z02_AnimateDemoPhase1Subphase0_Exit
    move.b  ($0415,A4),D0
    beq  _L_z02_AnimateDemoPhase1Subphase0_Exit
    moveq   #0,D0
    move.b  D0,($0415,A4)
    addq.b  #1,($042D,A4)
    even
_L_z02_AnimateDemoPhase1Subphase0_Exit:
    rts

    even
AnimateDemoPhase1Subphase1:
    addq.b  #1,($041A,A4)
    move.b  ($041A,A4),D0
    bne  _anon_z02_0
    addq.b  #1,($042D,A4)
_anon_z02_0:
    moveq   #41,D0
    move.b  D0,($041D,A4)
    moveq   #0,D0
    move.b  D0,($041C,A4)
    moveq   #43,D0
    move.b  D0,($0418,A4)
    move.b  #$E0,D0
    move.b  D0,($0417,A4)
    rts

    even
AnimateDemoPhase1Subphase2:
    jsr     HideAllSprites
    jsr     DisableFallenObjects
    jsr     Demo_AnimateObjects
    move.b  ($0015,A4),D0
    andi.b #$01,D0
    beq  _L_z02_AnimateDemoPhase1Subphase2_Exit
    moveq   #10,D2
    even
_L_z02_AnimateDemoPhase1Subphase2_DecObjYs:
    lea     ($0084,A4),A0
    subq.b  #1,(A0,D2.W)
    subq.b  #1,D2
    bne  _L_z02_AnimateDemoPhase1Subphase2_DecObjYs
    addq.b  #1,($041B,A4)
    move.b  ($041B,A4),D0
    bne  _anon_z02_1
    addq.b  #1,($0415,A4)
_anon_z02_1:
    move.b  ($0415,A4),D0
    cmpi.b  #$05,D0
    bne  _L_z02_AnimateDemoPhase1Subphase2_Scroll
    move.b  ($041B,A4),D0
    cmpi.b  #$80,D0
    bne  _L_z02_AnimateDemoPhase1Subphase2_Scroll
    addq.b  #1,($042D,A4)
    even
_L_z02_AnimateDemoPhase1Subphase2_Exit:
    rts

    even
_L_z02_AnimateDemoPhase1Subphase2_Scroll:
    addq.b  #1,($00FC,A4)
    move.b  ($00FC,A4),D0
    cmpi.b  #$F0,D0
    bne  _L_z02_AnimateDemoPhase1Subphase2_CheckLine
    addq.b  #1,($005C,A4)
    moveq   #0,D0
    move.b  D0,($00FC,A4)
    even
_L_z02_AnimateDemoPhase1Subphase2_CheckLine:
    move.b  ($041B,A4),D0
    andi.b #$07,D0
    bne  _L_z02_AnimateDemoPhase1Subphase2_Exit
    jsr     ProcessDemoLineItems
    ; Append a request to transfer a line.
    ; It's blank by default. Change it later.
    moveq   #32,D2
    move.b  #$FF,D0
    lea     ($0305,A4),A0
    move.b  D0,(A0,D2.W)
    subq.b  #1,D2
    even
_L_z02_AnimateDemoPhase1Subphase2_ClearLine:
    moveq   #36,D0
    lea     ($0305,A4),A0
    move.b  D0,(A0,D2.W)
    subq.b  #1,D2
    bpl  _L_z02_AnimateDemoPhase1Subphase2_ClearLine
    moveq   #32,D0
    move.b  D0,($0304,A4)
    move.b  ($041D,A4),D0
    move.b  D0,($0302,A4)
    move.b  ($041C,A4),D0
    move.b  D0,($0303,A4)
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$20,D1
    addx.b  D1,D0   ; ADC #$20 (X flag = 6502 C)
    move.b  D0,($041C,A4)
    bne  _L_z02_AnimateDemoPhase1Subphase2_CheckNTEnd
    addq.b  #1,($041D,A4)
    jmp     _L_z02_AnimateDemoPhase1Subphase2_CheckText

    even
_L_z02_AnimateDemoPhase1Subphase2_CheckNTEnd:
    ; Check if we reached the end of a nametable.
    ; If we did, then set the address to the top of the other one.
    ; $2BC0 -> $2000
    ; $23C0 -> $2800
    cmpi.b  #$C0,D0
    bne  _L_z02_AnimateDemoPhase1Subphase2_CheckText
    move.b  ($041D,A4),D0
    cmpi.b  #$2B,D0
    bne  _L_z02_AnimateDemoPhase1Subphase2_CheckNT0
    moveq   #32,D0
    move.b  D0,($041D,A4)
    jmp     _L_z02_AnimateDemoPhase1Subphase2_ResetVramLo

    even
_L_z02_AnimateDemoPhase1Subphase2_CheckNT0:
    cmpi.b  #$23,D0
    bne  _L_z02_AnimateDemoPhase1Subphase2_CheckText
    moveq   #40,D0
    move.b  D0,($041D,A4)
    even
_L_z02_AnimateDemoPhase1Subphase2_ResetVramLo:
    moveq   #0,D0
    move.b  D0,($041C,A4)
    even
_L_z02_AnimateDemoPhase1Subphase2_CheckText:
    ; Check text and NT attributes.
    ;
    moveq   #0,D2
    move.b  ($0419,A4),D2
    lea     (DemoLineAttrs).l,A0
    move.b  (A0,D2.W),D0
    andi.b #$80,D0
    beq  _L_z02_AnimateDemoPhase1Subphase2_ProcessAttrs
    ; PATCHED (P8): Replace broken NES indirect-pointer text lookup with
    ; direct M68K addressing. DemoLineTextAddrs contains word offsets.
    move.b  ($042E,A4),D0
    andi.w  #$00FF,D0
    lsl.w   #1,D0                ; * 2 for word-sized offset table
    lea     (DemoLineTextAddrs).l,A0
    move.w  (A0,D0.W),D0        ; D0.w = offset into DemoTextFields
    lea     (DemoTextFields).l,A0
    adda.w  D0,A0               ; A0 -> text field entry in ROM
    moveq   #0,D3               ; Y index into text field
    move.b  (A0,D3.W),D0        ; first byte = column offset
    moveq   #0,D2
    move.b  D0,D2
    even
_L_z02_AnimateDemoPhase1Subphase2_CopyLine:
    ; X (D2) = offset into destination line.
    ; Y (D3) = offset into source tiles of current text record.
    ; A0 = pointer to current text field (preserved across loop).
    addq.b  #1,D3
    move.b  (A0,D3.W),D0        ; read next tile from ROM
    cmpi.b  #$FF,D0
    beq  _L_z02_AnimateDemoPhase1Subphase2_EndLine
    lea     ($0305,A4),A1
    move.b  D0,(A1,D2.W)
    addq.b  #1,D2
    jmp     _L_z02_AnimateDemoPhase1Subphase2_CopyLine

    even
_L_z02_AnimateDemoPhase1Subphase2_EndLine:
    addq.b  #1,($042E,A4)
    even
_L_z02_AnimateDemoPhase1Subphase2_ProcessAttrs:
    ; Finished processing attribute $80.
    ;
    jsr     ProcessDemoLineAttrs
    addq.b  #1,($0419,A4)
    rts

    even
ProcessDemoLineAttrs:
    moveq   #0,D2
    move.b  ($0419,A4),D2
    lea     (DemoLineAttrs).l,A0
    move.b  (A0,D2.W),D0
    andi.b #$40,D0
    beq  _L_z02_ProcessDemoLineAttrs_Exit
    ; Append a second transfer record.
    ; This one is for nametable attributes.
    move.b  ($0418,A4),D0
    move.b  D0,($0325,A4)
    move.b  ($0417,A4),D0
    move.b  D0,($0326,A4)
    moveq   #72,D0
    move.b  D0,($0327,A4)
    moveq   #0,D0
    move.b  D0,($0328,A4)
    move.b  #$FF,D0
    move.b  D0,($0329,A4)
    addq.b  #1,($0416,A4)
    move.b  ($0417,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0417,A4)
    ; Check if we reached the end of nametable attributes.
    ; If we did, then set the address to the top of the other one.
    ; $2C00 -> $23C0
    ; $2400 -> $2BC0
    bne  _L_z02_ProcessDemoLineAttrs_Exit
    move.b  ($0418,A4),D0
    cmpi.b  #$23,D0
    bne  _L_z02_ProcessDemoLineAttrs_SetNT0
    moveq   #43,D0
    move.b  D0,($0418,A4)
    jmp     _L_z02_ProcessDemoLineAttrs_SetVramLo

    even
_L_z02_ProcessDemoLineAttrs_SetNT0:
    moveq   #35,D0
    move.b  D0,($0418,A4)
    even
_L_z02_ProcessDemoLineAttrs_SetVramLo:
    move.b  #$C0,D0
    move.b  D0,($0417,A4)
    even
_L_z02_ProcessDemoLineAttrs_Exit:
    rts

    even
DisableFallenObjects:
    ; For objects 1..10, indexed by X:
    ;
    moveq   #10,D2
    even
_L_z02_DisableFallenObjects_Loop:
    ; Once an object has fallen off the top of the screen,
    ; disable it.
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    ; The Y coordinate where we consider an object
    ; completely off the screen is $F0.
    cmpi.b  #$F0,D0
    bne  _L_z02_DisableFallenObjects_Next
    move.b  #$FF,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z02_DisableFallenObjects_Next:
    subq.b  #1,D2
    bne  _L_z02_DisableFallenObjects_Loop
    rts

    even
ProcessDemoLineItems:
    moveq   #0,D3
    move.b  ($0419,A4),D3
    lea     (DemoLineAttrs).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$20,D0
    bne  _L_z02_ProcessDemoLineItems_MakeObject
    rts

    even
_L_z02_ProcessDemoLineItems_MakeObject:
    moveq   #10,D2
    even
_L_z02_ProcessDemoLineItems_FindDisabled:
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z02_ProcessDemoLineItems_SetUpObject
    subq.b  #1,D2
    jmp     _L_z02_ProcessDemoLineItems_FindDisabled

    even
_L_z02_ProcessDemoLineItems_SetUpObject:
    moveq   #0,D3
    move.b  ($042F,A4),D3
    lea     (DemoLeftItemIds).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0444,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  #$EF,D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  (DemoItemColumnX1).l,D0
    move.b  D0,($70,A4,D2.W)
    moveq   #0,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$30,D0
    bcc  _L_z02_ProcessDemoLineItems_CenterLink
    subq.b  #1,D2
    lea     (DemoRightItemIds).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0444,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  #$EF,D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  (DemoItemColumnX2).l,D0
    move.b  D0,($70,A4,D2.W)
    moveq   #0,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    lea     (DemoLeftItemIds).l,A0
    move.b  (A0,D3.W),D0
    cmpi.b  #$1B,D0
    bne  _L_z02_ProcessDemoLineItems_IncRow
    ; Special case: The triforce must be centered.
    ; But it shows up in both column lists.
    ; Two objects were instantiated, but they'll overlap.
    moveq   #120,D0
    move.b  D0,($70,A4,D2.W)
    move.b  D0,($71,A4,D2.W)
    moveq   #0,D0
    move.b  D0,($0430,A4)
    even
_L_z02_ProcessDemoLineItems_IncRow:
    addq.b  #1,($042F,A4)
    rts

    even
_L_z02_ProcessDemoLineItems_CenterLink:
    moveq   #104,D0
    move.b  D0,($70,A4,D2.W)
    jmp     _L_z02_ProcessDemoLineItems_IncRow

    even
Demo_AnimateObjects:
    ; For each object 1..10, indexed by X:
    ;
    moveq   #10,D2
    even
_L_z02_Demo_AnimateObjects_LoopObject:
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z02_Demo_AnimateObjects_NextObject
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    ; Animate the fairy specially.
    ;
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$23,D0
    bne  _L_z02_Demo_AnimateObjects_AnimateNormal
    jsr     AnimateStationaryFairy
    jmp     _L_z02_Demo_AnimateObjects_PopAndNextObject

    even
_L_z02_Demo_AnimateObjects_AnimateNormal:
    ; Animate normal items (type < $30).
    ;
    cmpi.b  #$30,D0
    bcc  _L_z02_Demo_AnimateObjects_AnimateFinal
    jsr     AnimateItemObject
    jmp     _L_z02_Demo_AnimateObjects_PopAndNextObject

    even
_L_z02_Demo_AnimateObjects_AnimateFinal:
    ; At the end of the list of items are special items for Link
    ; and the sheet of paper.
    ;
    jsr     AnimateDemoStoryFinalItems
    even
_L_z02_Demo_AnimateObjects_PopAndNextObject:
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    even
_L_z02_Demo_AnimateObjects_NextObject:
    subq.b  #1,D2
    bne  _L_z02_Demo_AnimateObjects_LoopObject
    rts

; Unknown block
    dc.b    $A2, $04, $C9, $14, $D0, $02, $A2, $0C
    dc.b    $DE, $50, $02, $AA, $38, $E9, $04, $AA
    dc.b    $10, $F6, $60

    even
AnimateStationaryFairy:
    jsr     Anim_FetchObjPosForSpriteDescriptor
    jsr     Anim_SetSpriteDescriptorRedPaletteRow
    ; Rely on the fact that 2 represents normal sprite
    ; attributes with palette 6.
    ; Shift the value to make it 4.
    lsl.b  #1,D0   ; ASL A
    move.b  ($0015,A4),D1
    and.b  D1,D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    move.b  D0,($000C,A4)
    moveq   #20,D3
    jmp     Anim_WriteItemSprites

    even
AnimateDemoStoryFinalItems:
    ; The demo story ending objects use special item types.
    ; The bottom nibble of the item type is an index into two
    ; tables. Each row has 6 bytes, one for each sprite of the
    ; item type.
    ;
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    lsl.b  #1,D0   ; ASL A
    move.b  D0,($0000,A4)
    lsl.b  #1,D0   ; ASL A
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0000,A4),D1
    addx.b  D1,D0   ; ADC $00
    moveq   #0,D3
    move.b  D0,D3
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0000,A4)
    move.b  ($70,A4,D2.W),D0
    move.b  D0,($0001,A4)
    moveq   #5,D0
    move.b  D0,($0002,A4)
    move.b  D3,D0
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    moveq   #0,D2
    move.b  D0,D2
    even
_L_z02_AnimateDemoStoryFinalItems_LoopSprite:
    lea     (DemoStoryFinalSpriteTiles).l,A0
    move.b  (A0,D3.W),D0
    beq  _L_z02_AnimateDemoStoryFinalItems_SkipSprite
    lea     ($0201,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  ($0000,A4),D0
    lea     ($0200,A4),A0
    move.b  D0,(A0,D2.W)
    lea     (DemoStoryFinalSpriteAttrs).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0202,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  ($0001,A4),D0
