AnimateDemoPhase0Subphase0Artifacts:
    ; Set up sprites for the title.
    ; Copy initial sprite data to Sprites area.
    moveq   #112,D3
    even
_L_z02_AnimateDemoPhase0Subphase0Artifacts_CopySprites:
    lea     (InitialTitleSprites-1).l,A0
    move.b  (A0,D3.W),D0
    lea     ($01FF,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bne  _L_z02_AnimateDemoPhase0Subphase0Artifacts_CopySprites
    jsr     UpdateWaterfallAnimation
    ; When you reach the end of the glow cycle,
    ; Append a transfer record for the triforce palette.
    ;
    move.b  ($0412,A4),D0
    bne  _L_z02_AnimateDemoPhase0Subphase0Artifacts_DecGlowTimer
    moveq   #7,D3
