    lea     ($0302,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _L_z02_AnimateDemoPhase0Subphase0Artifacts_CopyTriforcePalette
    ; Patch the palette record with the color
    ; for the current point in the cycle.
    moveq   #0,D3
    move.b  ($0413,A4),D3
    lea     (TriforceGlowingColors).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0307,A4)
    moveq   #6,D0
    move.b  D0,($0412,A4)
    addq.b  #1,($0413,A4)
    move.b  ($0413,A4),D0
