AnimateDemoPhase0Subphase1:
    move.b  ($0438,A4),D0
    bne  _L_z02_AnimateDemoPhase0Subphase1_UpdateAnimation
    ; PATCHED (P6): Replace broken NES indirect-pointer math with direct
    ; M68K addressing. The original ADC #<label / ADC #>label that adds
    ; DemoPhase0Subphase1Palettes base address was lost in transpilation.
    moveq   #0,D0
    move.b  ($0437,A4),D0        ; cycle index (0-13)
    lsl.w   #5,D0                ; * 32 = byte offset into palette table
    lea     (DemoPhase0Subphase1Palettes).l,A0
    adda.w  D0,A0                ; A0 -> palette for this cycle
    ; Set up DynTileBuf header: $3F, $00, $20
    move.b  #$3F,($0302,A4)
    move.b  #$00,($0303,A4)
    moveq   #32,D0
    move.b  D0,($0304,A4)
    ; End marker at DynTileBuf+4+31
    moveq   #31,D3
    move.b  #$FF,D0
    lea     ($0306,A4),A1
    move.b  D0,(A1,D3.W)
    even
_L_z02_AnimateDemoPhase0Subphase1_CopyPalette:
    move.b  (A0,D3.W),D0        ; read from ROM palette table
    lea     ($0305,A4),A1
    move.b  D0,(A1,D3.W)
    subq.b  #1,D3
    bpl  _L_z02_AnimateDemoPhase0Subphase1_CopyPalette
    ; Advance the subphase cycle.
    ;
    addq.b  #1,($0437,A4)
    ; Set the timer to the delay for the current point in the cycle.
    ;
    moveq   #0,D3
    move.b  ($0437,A4),D3
    lea     (DemoPhase0Subphase1Delays-1).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0438,A4)
    cmpi.b  #$0E,D3
    bcs  _L_z02_AnimateDemoPhase0Subphase1_UpdateAnimation
    ; Advance to the next demo phase.
    ;
    addq.b  #1,($042C,A4)
    moveq   #0,D0
    move.b  D0,($042D,A4)
    move.b  D0,($0011,A4)
    even
_L_z02_AnimateDemoPhase0Subphase1_UpdateAnimation:
    subq.b  #1,($0438,A4)
    jsr     UpdateWaterfallAnimation
    rts

