    andi.b #$0F,D0
    cmpi.b  #$01,D0
    bne  _L_z02_ModeE_HandleDirectionButton_Left
    ; Pressed Right.
    ;
    ; Increase CharBoardIndex [$041F] to put cursor at character to the right.
    ;
    addq.b  #1,($041F,A4)
    move.b  ($0071,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$10,D1
    addx.b  D1,D0   ; ADC #$10 (X flag = 6502 C)
    move.b  D0,($0071,A4)
    cmpi.b  #$E0,D0
    bne  _anon_z02_11
    moveq   #48,D0
    move.b  D0,($0071,A4)
    moveq   #0,D2
    jsr     CycleCharBoardCursorY
    move.b  ($042A,A4),D0
    beq  _anon_z02_11
    moveq   #0,D0
    move.b  D0,($041F,A4)
_anon_z02_11:
    jmp     _L_z02_ModeE_HandleDirectionButton_FinishInput

    even
_L_z02_ModeE_HandleDirectionButton_Left:
    cmpi.b  #$02,D0
    bne  _L_z02_ModeE_HandleDirectionButton_Down
    ; Pressed Left.
    ;
    ; Decrease CharBoardIndex [$041F] to put cursor at character to the left.
    ;
    subq.b  #1,($041F,A4)
    move.b  ($0071,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$10,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$10
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($0071,A4)
    cmpi.b  #$20,D0
    bne  _anon_z02_12
    move.b  #$D0,D0
    move.b  D0,($0071,A4)
    moveq   #3,D2
    jsr     CycleCharBoardCursorY
    move.b  ($042A,A4),D0
    beq  _anon_z02_12
    moveq   #43,D0
    move.b  D0,($041F,A4)
_anon_z02_12:
    jmp     _L_z02_ModeE_HandleDirectionButton_FinishInput

    even
_L_z02_ModeE_HandleDirectionButton_Down:
    cmpi.b  #$04,D0
    bne  _L_z02_ModeE_HandleDirectionButton_Up
    ; Pressed Down.
    ;
    ; Increase CharBoardIndex [$041F] by $B (one row down).
    ;
    move.b  ($041F,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$0B,D1
    addx.b  D1,D0   ; ADC #$0B (X flag = 6502 C)
    move.b  D0,($041F,A4)
    moveq   #0,D2
    jsr     CycleCharBoardCursorY
    move.b  ($042A,A4),D0
    beq  _L_z02_ModeE_HandleDirectionButton_Finish
    move.b  ($041F,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$2C,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$2C
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($041F,A4)
    even
_L_z02_ModeE_HandleDirectionButton_Finish:
    jmp     _L_z02_ModeE_HandleDirectionButton_FinishInput

    even
_L_z02_ModeE_HandleDirectionButton_Up:
    cmpi.b  #$08,D0
    bne  _L_z02_ModeE_HandleDirectionButton_Exit
    ; Pressed Up.
    ;
    ; Decrease CharBoardIndex [$041F] by $B (one row up).
    ;
    move.b  ($041F,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$0B,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$0B
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($041F,A4)
    moveq   #3,D2
    jsr     CycleCharBoardCursorY
    move.b  ($042A,A4),D0
    beq  _L_z02_ModeE_HandleDirectionButton_FinishInput
    move.b  ($041F,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$2C,D1
    addx.b  D1,D0   ; ADC #$2C (X flag = 6502 C)
    move.b  D0,($041F,A4)
    even
_L_z02_ModeE_HandleDirectionButton_FinishInput:
    ; PATCH P25: P13 sync call DISABLED for FS2-F console freeze
    moveq   #1,D0
    move.b  D0,($0428,A4)
    move.b  D0,($0602,A4)
    even
_L_z02_ModeE_HandleDirectionButton_Exit:
    rts

; Params:
; X: 0 for down, 3 for up.
;
; Returns:
; ModeE_WrappedAroundBoardY [$042A]=1 if wrapped arounnd.
;
; Assume we don't wrap around.
    even
CycleCharBoardCursorY:
    moveq   #0,D3
    move.b  ($0085,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (ModeE_CharBoardYOffsetsAndBounds).l,A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC ModeE_CharBoardYOffsetsAndBounds,X
    move.b  D0,($0085,A4)
    addq.b  #1,D2
    lea     (ModeE_CharBoardYOffsetsAndBounds).l,A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    bne  _L_z02_CycleCharBoardCursorY_ReturnValue
    addq.b  #1,D2
    lea     (ModeE_CharBoardYOffsetsAndBounds).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0085,A4)
    addq.b  #1,D3
    even
_L_z02_CycleCharBoardCursorY_ReturnValue:
    move.b  D3,($042A,A4)
    even
LA10A_Exit:
    rts

; PATCH P13: ModeE_SyncCharBoardCursorToIndex (Attempt 6a part 2).
; Source-of-truth sync for the char board cursor.  Normalizes
; CharBoardIndex ($041F) mod 44, snaps the hidden slot (idx 43)
; to idx 9, and regenerates (ObjX=$0071, ObjY=$0085) from the
; index using row = idx/11, col = idx%11, ObjX = $30+col*$10,
; ObjY = $87+row*$10.  Call this after any direction move.
    even
ModeE_SyncCharBoardCursorToIndex:
    move.l  D0,-(A7)
    move.l  D1,-(A7)
    move.b  ($041F,A4),D0
    btst    #7,D0
    beq.s   .p13_ck_high
    addi.b  #44,D0         ; underflow wrap (-1 -> 43)
.p13_ck_high:
    cmpi.b  #44,D0
    bcs.s   .p13_ck_hidden
    subi.b  #44,D0         ; overflow wrap
.p13_ck_hidden:
    cmpi.b  #43,D0
    bne.s   .p13_compute
    moveq   #9,D0          ; hidden slot -> idx 9
.p13_compute:
    move.b  D0,($041F,A4)
    moveq   #0,D1
.p13_row_loop:
    cmpi.b  #11,D0
    bcs.s   .p13_row_done
    subi.b  #11,D0
    addq.b  #1,D1
    bra.s   .p13_row_loop
.p13_row_done:
    lsl.b   #4,D0
    addi.b  #$30,D0
    move.b  D0,($0071,A4)
    lsl.b   #4,D1
    addi.b  #$88,D1         ; PATCH P26: Phase 10 FS2-B Y base +1 px
    move.b  D1,($0085,A4)
    move.l  (A7)+,D1
    move.l  (A7)+,D0
    rts

    even
ModeE_HandleAOrB:
    move.b  ($0420,A4),D0
    ; If InitializedNameField [$0420] is set, then skip initializing
    ; the name field.
    bne  _L_z02_ModeE_HandleAOrB_CheckAB
    moveq   #0,D3
    move.b  ($0016,A4),D3
    cmpi.b  #$03,D3
    bne.s  __far_z_02_0008
    jmp  LA10A_Exit
__far_z_02_0008:
    ; Set NameCharOffset [$0421] to the offset of first char
    ; in the current slot's name.
    lea     (SlotToNameOffset).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0421,A4)
    ; Get the offset of the end of the initial name character
    ; transfer record header for the current slot.
    moveq   #0,D2
    lea     (SlotToInitialNameCharTransferHeaderEndOffsets).l,A0
    move.b  (A0,D3.W),D2
    moveq   #2,D3
    even
_L_z02_ModeE_HandleAOrB_CopyHeaderTemplate:
    lea     (SlotToInitialNameCharTransferHeaders).l,A0
    move.b  (A0,D2.W),D0
    lea     ($0422,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D2
    subq.b  #1,D3
    bpl  _L_z02_ModeE_HandleAOrB_CopyHeaderTemplate
    addq.b  #1,($0420,A4)
    even
_L_z02_ModeE_HandleAOrB_CheckAB:
    ; At this point:
    ; - NameCharOffset [$0421] holds the offset of the first character in the save slot info name for the current slot.
    ;   - This will be changed as the player inputs characters.
    ; - [$0422] to [$0424] hold a transfer record header. The VRAM address points to the beginning of the appropriate name field in the nametable.
    ;   - This will be changed as the player inputs characters.
    ; - InitializedNameField [$0420] is set to 1.
    ;
    move.b  ($00F8,A4),D0
    andi.b #$C0,D0
    beq  _L_z02_ModeE_HandleAOrB_Exit
    ; A or B was pressed.
    ;
    cmpi.b  #$40,D0  ; PATCH P29: swap so NES-B (Gen A) = write, NES-A (Gen B) = bksp
    bne  _L_z02_ModeE_HandleAOrB_Backspace   ; PATCH P25b: B = backspace
    ; A was pressed.
    ;
    ; Request to play the character click tune (same as bomb set).
    moveq   #32,D3
    move.b  D3,($0604,A4)
    moveq   #2,D3
    even
_L_z02_ModeE_HandleAOrB_CopyHeader:
    lea     ($0422,A4),A0
    move.b  (A0,D3.W),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _L_z02_ModeE_HandleAOrB_CopyHeader
    move.b  D3,($0306,A4)
    moveq   #0,D2
    move.b  ($0421,A4),D2
    moveq   #0,D3
    move.b  ($041F,A4),D3
    lea     (ModeE_CharMap).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0305,A4)
    lea     ($0638,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z02_ModeE_HandleAOrB_MoveCursor:
    move.b  ($0070,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0070,A4)
    addq.b  #1,($0421,A4)
    addq.b  #1,($0423,A4)
    ; If VRAM address still points inside the name field,
    ; then go finish.
    ;
    ; The idea is that each name field in nametable begins at
    ; an address ending in $E. For example, slot 0 has a name
    ; at VRAM addresses $20CE to $20D5.
    ;
    ; Once the $E becomes a 6, we've gone past the end of
    ; the name field.
    ;
    ; Keep in mind that [0423] is the second byte of the transfer
    ; record header.
    ;
    move.b  ($0070,A4),D0      ; PATCH P14: Zelda16.11
    cmpi.b  #$B0,D0
    bne  _L_z02_ModeE_HandleAOrB_Exit
    ; The VRAM address now points outside the name field.
    ; So, wrap around to the beginning of the name field.
    ;
    ; For example, $20D6 -> $20CE.
    ;
    move.b  ($0423,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$08,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$08
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($0423,A4)
    ; It also means that we went past the end of the save slot
    ; info name. Set the offset to the beginning of the name.
    moveq   #0,D3
    move.b  ($0016,A4),D3
    lea     (SlotToNameOffset).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0421,A4)
    ; If the name cursor has gone past the end of the field,
    ; then wrap around.
    move.b  ($0070,A4),D0
    cmpi.b  #$B0,D0
    bne  _L_z02_ModeE_HandleAOrB_Exit
    moveq   #112,D0
    move.b  D0,($0070,A4)
    even
; PATCH P25b: FS2-E backspace handler.
; Entered when bit $40 (B) is set in $00F8 & $C0. Decrements
; NameCharOffset, VRAM low byte, and name cursor sprite X by
; one column (8 px), and writes a space ($24) to the erased
; position. Clamps at SlotToNameOffset[$0016] so the backspace
; cannot cross into a previous slot's name field.
_L_z02_ModeE_HandleAOrB_Backspace:
    moveq   #0,D3
    move.b  ($0016,A4),D3        ; D3 = current slot
    lea     (SlotToNameOffset).l,A0
    move.b  (A0,D3.W),D1         ; D1 = slot start offset
    move.b  ($0421,A4),D0        ; D0 = current NameCharOffset
    cmp.b   D1,D0
    bls     _L_z02_ModeE_HandleAOrB_Exit   ; at/below start, no-op
    subq.b  #1,D0
    move.b  D0,($0421,A4)        ; NameCharOffset -= 1
    subq.b  #1,($0423,A4)        ; VRAM low byte -= 1
    move.b  ($0070,A4),D1
    subi.b  #8,D1
    move.b  D1,($0070,A4)        ; name cursor X -= 8
    moveq   #$24,D1              ; space tile
    moveq   #0,D3
    move.b  D0,D3                ; D3 = erased offset
    lea     ($0638,A4),A0
    move.b  D1,(A0,D3.W)         ; namebuf[offset] = space
    jmp     _L_z02_ModeE_HandleAOrB_Exit
    even
_L_z02_ModeE_HandleAOrB_Exit:
    jmp     ModeE_SetNameCursorSpriteX

    even
ModeEandF_SetUpCursorSprites:
    ; Copy almost 3 sprite records ($B bytes) to byte 1 of
    ; Sprites block. Only sprite 0 byte 0 is missing.
    ; These are the cursor sprites.
    moveq   #10,D3
    even
_L_z02_ModeEandF_SetUpCursorSprites_CopySprites:
    lea     (ModeEandFCursorSprites).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0201,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _L_z02_ModeEandF_SetUpCursorSprites_CopySprites
    moveq   #0,D3
    move.b  ($0016,A4),D3
    lea     (ModeEandFSlotCursorYs).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0084,A4)
    move.b  D0,($0200,A4)
    move.b  ($0012,A4),D0
    cmpi.b  #$0F,D0
    ; There's more work in mode $E.
    ; The name cursor position is held in ObjX/ObjY[0].
    ; The char-board cursor position is held in ObjX/ObjY[1].
    beq  _L_z02_ModeEandF_SetUpCursorSprites_Exit
    move.b  #$F3,D0
    move.b  D0,($0201,A4)
    ; Because the visible part of the cursor block sprite is
    ; in the bottom, move the name cursor's sprite 8 pixels
    ; above its ObjY.
    move.b  ($0084,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$08,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$08
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($0204,A4)
    moveq   #112,D0
    move.b  D0,($0070,A4)
    move.b  #$87,D0
    move.b  D0,($0085,A4)
    moveq   #48,D0
    move.b  D0,($0071,A4)
    even
_L_z02_ModeEandF_SetUpCursorSprites_Exit:
    rts

    even
ModeEandF_WriteNameCursorSpritePosition:
    move.b  ($0084,A4),D0
    cmpi.b  #$77,D0
    bne  _L_z02_ModeEandF_WriteNameCursorSpritePosition_WriteCursorY
    move.b  #$F8,D0
    move.b  D0,($0204,A4)
    rts

    even
_L_z02_ModeEandF_WriteNameCursorSpritePosition_WriteCursorY:
    move.b  ($0084,A4),D0
    jsr     ModifyFlashingCursorY
    move.b  D3,($0204,A4)
    even
ModeE_SetNameCursorSpriteX:
    move.b  ($0070,A4),D0
    move.b  D0,($0207,A4)
    rts

    even
ModeEandF_WriteCharBoardCursorSpritePosition:
    move.b  ($0084,A4),D0
    cmpi.b  #$77,D0
    bne  _L_z02_ModeEandF_WriteCharBoardCursorSpritePosition_WriteCursorCoords
    move.b  #$F8,D0
    move.b  D0,($0208,A4)
    rts

    even
_L_z02_ModeEandF_WriteCharBoardCursorSpritePosition_WriteCursorCoords:
    move.b  ($0085,A4),D0
    jsr     ModifyFlashingCursorY
    move.b  D3,($0208,A4)
    move.b  ($0071,A4),D0
    move.b  D0,($020B,A4)
    rts

; Params:
; A: cursor Y
;
; Returns:
; Y: adjusted cursor Y, or $F8 to hide it
;
; Description:
; Adjust the Y coordinate to account for the visible part of
; block cursor being in the bottom half of sprite.
; Also, make the cursor flash.
;
    even
ModifyFlashingCursorY:
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$08,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$08
    eori    #$10,CCR  ; restore X = 6502 C
    moveq   #0,D3
    move.b  D0,D3
    move.b  ($0015,A4),D0
    andi.b #$08,D0
    bne  _anon_z02_13
    move.b  #$F8,D3
_anon_z02_13:
    rts

    even
UpdateModeEandF_Idle:
    move.b  ($00F8,A4),D0
    andi.b #$20,D0
    beq  _L_z02_UpdateModeEandF_Idle_Exit
    even
_L_z02_UpdateModeEandF_Idle_ChangeSelection:
    moveq   #1,D0
    move.b  D0,($0602,A4)
    addq.b  #1,($0016,A4)
    moveq   #0,D3
    move.b  ($0016,A4),D3
    cmpi.b  #$04,D3
    bne  _anon_z02_14
    moveq   #0,D3
    move.b  D3,($0016,A4)
_anon_z02_14:
    lea     (ModeEandFSlotCursorYs).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0200,A4)
    move.b  ($0012,A4),D0
    cmpi.b  #$0F,D0
    beq  _L_z02_UpdateModeEandF_Idle_Exit
    move.b  ($0084,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$18,D1
    addx.b  D1,D0   ; ADC #$18 (X flag = 6502 C)
    move.b  D0,($0084,A4)
    cmpi.b  #$8F,D0
    bne  _anon_z02_15
    moveq   #47,D0
    move.b  D0,($0084,A4)
_anon_z02_15:
    move.b  D0,($0200,A4)
    moveq   #112,D0
    move.b  D0,($0207,A4)
    move.b  D0,($0070,A4)
    moveq   #0,D0
    move.b  D0,($0420,A4)
    move.b  D0,($0421,A4)
    moveq   #0,D3
    move.b  ($0016,A4),D3
    cmpi.b  #$03,D3
    beq  _L_z02_UpdateModeEandF_Idle_Exit
    lea     ($0633,A4),A0
    move.b  (A0,D3.W),D0
    bne  _L_z02_UpdateModeEandF_Idle_ChangeSelection
    even
_L_z02_UpdateModeEandF_Idle_Exit:
    rts

    even
Mode1SlotLineTransferBuf:
    dc.b    $21, $09, $11, $24, $24, $24, $24, $24
    dc.b    $24, $24, $24, $62, $00, $00, $00, $00
    dc.b    $00, $00, $00, $00, $21, $32, $08, $00
    dc.b    $00, $00, $00, $00, $00, $00, $00, $FF

