    dc.l    InitMode1_FillAndTransferSlotTiles   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    InitMode1_FillAndTransferSlotTiles   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    InitMode1_FillAndTransferSlotTiles   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    InitMode1_Sub6   ; jump table entry (32-bit for _m68k_tablejump)

    even
UpdateMode0Demo_Sub1:
    ; For each save slot:
    ;   If file B is uncommitted and valid, then
    ;     Copy file B to file A (also marks file B committed)
    ;   If file A's static markers are wrong or file is invalid, then
    ;     Format file A
    ;
    ; TODO: This is also mode 1 submode 0 init.
    ;
    jsr     TurnOffAllVideo
    moveq   #0,D0
    move.b  D0,($0016,A4)
    even
_L_z02_UpdateMode0Demo_Sub1_LoopSlot:
    moveq   #0,D3
    move.b  ($0016,A4),D3
