    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    move.b  ($CC,A4),D1   ; ptr lo
    move.b  ($CD,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    jsr     FetchFileBAddressSet
    jsr     CalculateFileBChecksum
    move.b  #$FF,D0
    moveq   #0,D3
    move.b  ($0016,A4),D3
    lea     (NES_SRAM+$052A).l,A0
    move.b  D0,(A0,D3.W)
    rts

