InitMode1_Sub1:
    ; Reset CurSaveSlot. Doing this is useful for the
    ; work done here, and for the sequence of submodes
    ; that generate and transfer save slot graphics.
    moveq   #0,D0
    move.b  D0,($0016,A4)
    jsr     FetchFileAAddressSet
    moveq   #11,D3
    moveq   #0,D2
    even
_L_z02_InitMode1_Sub1_LoopSlot:
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    moveq   #0,D3
    move.b  D0,D3
    lea     (LinkColors).l,A0
    move.b  (A0,D3.W),D0
