    lea     (MenuPalettesTransferBuf+20).l,A0
    move.b  D0,(A0,D2.W)
    move.b  (A5)+,D0  ; PLA
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$28,D1
    addx.b  D1,D0   ; ADC #$28 (X flag = 6502 C)
    moveq   #0,D3
    move.b  D0,D3
    move.b  D2,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$04,D1
    addx.b  D1,D0   ; ADC #$04 (X flag = 6502 C)
    moveq   #0,D2
    move.b  D0,D2
    cmpi.b  #$0C,D2
    bcs  _L_z02_InitMode1_Sub1_LoopSlot
    jsr     ResetRoomTileObjInfo
    moveq   #18,D0
    move.b  D0,($0014,A4)
    addq.b  #1,($0013,A4)
    jsr     TurnOffVideoAndClearArtifacts
    moveq   #4,D3
    moveq   #0,D0
    move.b  D0,($0529,A4)
_anon_z02_20:
    lea     ($0621,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _anon_z02_20
    rts

