InitMode1_FillAndTransferSlotTiles:
    ; Copy the mode 1 line transfer buf template to
    ; dynamic transfer buf.
    moveq   #31,D3
    even
_L_z02_InitMode1_FillAndTransferSlotTiles_CopySlotLineTemplate:
    lea     (Mode1SlotLineTransferBuf).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _L_z02_InitMode1_FillAndTransferSlotTiles_CopySlotLineTemplate
    moveq   #0,D3
    move.b  ($0016,A4),D3
    even
_L_z02_InitMode1_FillAndTransferSlotTiles_OffsetSlotLineAddr:
    move.b  ($0303,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$60,D1
    addx.b  D1,D0   ; ADC #$60 (X flag = 6502 C)
    move.b  D0,($0303,A4)
    move.b  ($0317,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$60,D1
    addx.b  D1,D0   ; ADC #$60 (X flag = 6502 C)
    move.b  D0,($0317,A4)
    move.b  ($0302,A4),D0
    move.b  #$00,D1
    addx.b  D1,D0   ; ADC #$00 (X flag = 6502 C)
    move.b  D0,($0302,A4)
    move.b  D0,($0316,A4)
    subq.b  #1,D3
    bpl  _L_z02_InitMode1_FillAndTransferSlotTiles_OffsetSlotLineAddr
    ; Copy name of current slot to beginning of payload
    ; of first record in dynamic transfer buf.
    move.b  ($0016,A4),D0
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    moveq   #0,D2
    move.b  D0,D2
    moveq   #3,D3
    even
_L_z02_InitMode1_FillAndTransferSlotTiles_CopyName:
    lea     ($0638,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D3.W)
    addq.b  #1,D2
    addq.b  #1,D3
    cmpi.b  #$0B,D3
    bne  _L_z02_InitMode1_FillAndTransferSlotTiles_CopyName
    ; Copy heart values from current save slot info
    ; to [$0E:0F] for formatting.
    move.b  ($0016,A4),D0
    lsl.b  #1,D0   ; ASL A
    moveq   #0,D3
    move.b  D0,D3
    lea     ($0650,A4),A0
    move.b  (A0,D3.W),D0
    move.b  D0,($000E,A4)
    addq.b  #1,D3
    lea     ($0650,A4),A0
    move.b  (A0,D3.W),D0
    move.b  D0,($000F,A4)
    moveq   #12,D3
    jsr     FormatHeartsInTextBuf
    addq.b  #1,($0016,A4)
    addq.b  #1,($0013,A4)
    rts

    even
InitMode1_Sub6:
    ; Copy the mode 1 death counts transfer buf template to
    ; dynamic transfer buf.
    moveq   #18,D3
    even
_L_z02_InitMode1_Sub6_CopyTemplate:
    lea     (Mode1DeathCountsTransferBuf).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _L_z02_InitMode1_Sub6_CopyTemplate
    moveq   #0,D0
    move.b  D0,($000A,A4)
    moveq   #3,D0
    move.b  D0,($000B,A4)
    even
_L_z02_InitMode1_Sub6_LoopSlot:
    moveq   #0,D3
    move.b  ($000A,A4),D3
    lea     ($0630,A4),A0
    move.b  (A0,D3.W),D0
    jsr     FormatDecimalByte
    moveq   #0,D2
    move.b  ($000B,A4),D2
    move.b  ($0001,A4),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  ($0002,A4),D0
    lea     ($0303,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  ($0003,A4),D0
    bne  _L_z02_InitMode1_Sub6_EmitChar
    ; If the first or second characters weren't spaces,
    ; then go ahead and emit the '0'.
    move.b  ($0001,A4),D0
    cmpi.b  #$24,D0
    bne  _L_z02_InitMode1_Sub6_Emit0
    move.b  ($0002,A4),D0
    cmpi.b  #$24,D0
    bne  _L_z02_InitMode1_Sub6_Emit0
    moveq   #0,D3
    move.b  ($000A,A4),D3
    lea     ($0633,A4),A0
    move.b  (A0,D3.W),D0
    bne  _L_z02_InitMode1_Sub6_Emit0
    moveq   #36,D0
    bne  _L_z02_InitMode1_Sub6_EmitChar
    even
_L_z02_InitMode1_Sub6_Emit0:
    moveq   #0,D0
    even
_L_z02_InitMode1_Sub6_EmitChar:
    lea     ($0304,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D2,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$06,D1
    addx.b  D1,D0   ; ADC #$06 (X flag = 6502 C)
    move.b  D0,($000B,A4)
    addq.b  #1,($000A,A4)
    move.b  ($000A,A4),D0
    cmpi.b  #$03,D0
    bne  _L_z02_InitMode1_Sub6_LoopSlot
    move.b  #$FF,D3
    move.b  D3,($0016,A4)
    move.b  D3,($0526,A4)
    even
_L_z02_InitMode1_Sub6_FindActiveSlot:
    addq.b  #1,D3
    addq.b  #1,($0016,A4)
    lea     ($0633,A4),A0
    move.b  (A0,D3.W),D0
    beq  _L_z02_InitMode1_Sub6_FindActiveSlot
    moveq   #0,D0
    move.b  D0,($0013,A4)
    addq.b  #1,($0011,A4)
    clr.b   ($00FF083D).l       ; PATCH P11: release VRamForceBlankGate
