    dc.l    UpdateMode1Menu_Sub1   ; jump table entry (32-bit for _m68k_tablejump)

    even
UpdateMode1Menu_Sub0:
    tst.b   ($00FF042B).l          ; PATCH P12: FrontendStartReleaseGate
    beq.s   .p12_mode1_sub0_pass
    move.b  ($00F8,A4),D0
    andi.b  #$10,D0
    beq.s   .p12_mode1_sub0_release
    rts                             ; Start still held -> stay in Sub0
.p12_mode1_sub0_release:
    clr.b   ($00FF042B).l          ; Start released -> clear gate
.p12_mode1_sub0_pass:
    move.b  ($00F8,A4),D0
    andi.b #$10,D0
    bne  _L_z02_UpdateMode1Menu_Sub0_Exit
    move.b  ($00F8,A4),D0
    andi.b #$20,D0
    beq  _anon_z02_21
    even
_L_z02_UpdateMode1Menu_Sub0_ChangeSelection:
    moveq   #1,D0
    move.b  D0,($0602,A4)
    addq.b  #1,($0016,A4)
    move.b  ($0016,A4),D0
    cmpi.b  #$05,D0
    bne  _anon_z02_21
    moveq   #0,D0
    move.b  D0,($0016,A4)
_anon_z02_21:
    moveq   #0,D3
    move.b  ($0016,A4),D3
    ; Since CurSaveSlot is used to index menu choices, which
    ; includes register and eliminate in addition to save slots;
    ; the IsSaveSlotActive array includes elements at the end
    ; for these options.
    lea     ($0633,A4),A0
    move.b  (A0,D3.W),D0
    beq  _L_z02_UpdateMode1Menu_Sub0_ChangeSelection
    moveq   #2,D3
    even
_L_z02_UpdateMode1Menu_Sub0_WriteCursorSprite:
    lea     (Mode1CursorSpriteTriplet).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0201,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _L_z02_UpdateMode1Menu_Sub0_WriteCursorSprite
    moveq   #0,D3
    move.b  ($0016,A4),D3
    lea     (Mode1CursorSpriteYs).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0200,A4)
    moveq   #88,D0
    move.b  D0,($0001,A4)
    moveq   #48,D0
    move.b  D0,($0000,A4)
    jmp     Mode1_WriteLinkSprites

    even
_L_z02_UpdateMode1Menu_Sub0_Exit:
    addq.b  #1,($0013,A4)
    rts

    even
UpdateMode1Menu_Sub1:
    moveq   #0,D0
    move.b  D0,($0607,A4)
    moveq   #0,D0
    move.b  D0,($0010,A4)
    move.b  D0,($0656,A4)
    jsr     TurnOffAllVideo
    move.b  ($0016,A4),D0
    cmpi.b  #$03,D0
    bcs  _L_z02_UpdateMode1Menu_Sub1_ChoseSlot
    move.b  ($0016,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$0B,D1
    addx.b  D1,D0   ; ADC #$0B (X flag = 6502 C)
    move.b  D0,($0012,A4)
    jmp     EndGameMode

    even
_L_z02_UpdateMode1Menu_Sub1_ChoseSlot:
    ; The player chose a save slot.
    ;
    jsr     TurnOffAllVideo
    jsr     FetchFileAAddressSet
    moveq   #39,D3
    even
_L_z02_UpdateMode1Menu_Sub1_CopyItems:
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    lea     ($0657,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _L_z02_UpdateMode1Menu_Sub1_CopyItems
    moveq   #0,D0
    move.b  D0,($052E,A4)
    move.b  D0,($00AC,A4)
    move.b  D0,($066C,A4)
