    ;
    moveq   #0,D3
    move.b  D0,D3
    even
_L_z02_UpdateMode1Menu_Sub1_CopyWorldFlags:
    move.b  ($02,A4),D1   ; ptr lo
    move.b  ($03,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    move.b  ($0E,A4),D1   ; ptr lo
    move.b  ($0F,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    addq.b  #1,($0002,A4)
    bne  _anon_z02_22
    addq.b  #1,($0003,A4)
_anon_z02_22:
    addq.b  #1,($000E,A4)
    bne  _anon_z02_23
    addq.b  #1,($000F,A4)
_anon_z02_23:
    move.b  ($000E,A4),D0
    cmpi.b  #$FF,D0
    bne  _L_z02_UpdateMode1Menu_Sub1_CopyWorldFlags
    move.b  ($000F,A4),D0
    cmpi.b  #$07,D0
    bne  _L_z02_UpdateMode1Menu_Sub1_CopyWorldFlags
