Mode1_WriteLinkSprites:
    moveq   #8,D0
    move.b  D0,($0002,A4)
    moveq   #10,D0
    move.b  D0,($0003,A4)
    ; [$04] is used as an index and sprite attributes.
    ; It takes on values 0 to 2.
    ; As an index, it represents a save slot.
    ; As attributes, these values represent palettes 4 to 6.
    moveq   #0,D0
    jsr     Anim_SetSpriteDescriptorAttributes
    ; We want to start with sprite 4 (offset $10).
    ; Begin with 8, so that the loop will add 8 and
    ; put us at the offset we want.
    moveq   #8,D0
    move.b  D0,($0343,A4)
    even
_L_z02_Mode1_WriteLinkSprites_LoopSlot:
    move.b  ($0343,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0343,A4)
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$04,D1
    addx.b  D1,D0   ; ADC #$04 (X flag = 6502 C)
    move.b  D0,($0344,A4)
    moveq   #1,D0
    move.b  D0,($0007,A4)
    moveq   #8,D0
    move.b  D0,($000A,A4)
    move.b  ($0000,A4),D0
    move.b  D0,-(A5)  ; PHA
    move.w  ($0004,A4),D1       ; PATCH P30: save $04/$05
    move.w  D1,-(A7)            ; PATCH P30: push to stack
    clr.w   ($0004,A4)          ; PATCH P30: pin Link attr=0 (bank A = green)
    jsr     Anim_WriteSpritePairNotFlashing
    move.w  (A7)+,D1            ; PATCH P30: pop
    move.w  D1,($0004,A4)       ; PATCH P30: restore slot index
    moveq   #0,D2
    move.b  D0,D2
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($0000,A4)
    moveq   #0,D3
    move.b  ($0004,A4),D3
    lea     ($062D,A4),A0
    move.b  (A0,D3.W),D0
    beq  _L_z02_Mode1_WriteLinkSprites_NextSlot
    moveq   #0,D3
    move.b  ($0343,A4),D3
    move.b  ($0001,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$03,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$03
    eori    #$10,CCR  ; restore X = 6502 C
    lea     ($0280,A4),A0
    move.b  D0,(A0,D3.W)
    moveq   #32,D0
    lea     ($0281,A4),A0
    move.b  D0,(A0,D3.W)
    moveq   #3,D0
    lea     ($0282,A4),A0
    move.b  D0,(A0,D3.W)
    move.b  ($0000,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$0C,D1
    addx.b  D1,D0   ; ADC #$0C (X flag = 6502 C)
    lea     ($0283,A4),A0
    move.b  D0,(A0,D3.W)
    even
_L_z02_Mode1_WriteLinkSprites_NextSlot:
    move.b  ($0001,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$18,D1
    addx.b  D1,D0   ; ADC #$18 (X flag = 6502 C)
    move.b  D0,($0001,A4)
    addq.b  #1,($0004,A4)
    addq.b  #1,($0005,A4)
    move.b  ($0004,A4),D0
    cmpi.b  #$03,D0
    bne  _L_z02_Mode1_WriteLinkSprites_LoopSlot
    rts

