    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    subq.b  #1,D3
    bpl  _L_z02_UpdateModeDSave_Sub0_CopyItems
    moveq   #0,D3
    move.b  ($0016,A4),D3
    lea     ($0630,A4),A0
    move.b  (A0,D3.W),D0
    moveq   #0,D3
    move.b  ($CA,A4),D1   ; ptr lo
    move.b  ($CB,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
