DrawLinkZeldaTriforces:
    ; The triforce over Link goes in the room object slot $13.
    ; Set its location $10 pixels above Link.
    ;
    move.b  ($0070,A4),D0
    move.b  D0,($0083,A4)
    move.b  ($0084,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$10,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$10
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($0097,A4)
    ; Draw Link.
    ;
    moveq   #0,D2
    jsr     Anim_FetchObjPosForSpriteDescriptor
    jsr     Anim_SetSpriteDescriptorAttributes
    move.b  D0,($000C,A4)
    moveq   #72,D0
    move.b  D0,($0343,A4)
    moveq   #76,D0
    move.b  D0,($0344,A4)
