    ; Draw triforce over Link.
    ;
    moveq   #27,D0
    moveq   #19,D2
    jsr     AnimateItemObject
    moveq   #1,D2
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; Draw Zelda.
