    ; The triforce over Zelda goes in slot 2.
    ; Set its location $10 pixels above her.
    ;
    move.b  ($0071,A4),D0
    move.b  D0,($0072,A4)
    move.b  ($0085,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$10,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$10
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($0086,A4)
    ; Draw triforce over Zelda.
