    dc.b    $1D, $1E, $1B, $17, $1C, $24, $1D, $18
    dc.b    $24, $11, $22, $1B, $1E, $15, $0E, $2C
    dc.b    $1D, $11, $12, $1C, $24, $0E, $17, $0D
