UpdatePeaceTextbox:
    ; Only emit a character once every 8 frames --
    ; when (counter [0412] MOD 8) = 4.
    ;
    addq.b  #1,($0412,A4)
    move.b  ($0412,A4),D0
    andi.b #$07,D0
    cmpi.b  #$04,D0
    bne  _L_z02_UpdatePeaceTextbox_Exit
    ; Copy the 5 bytes of the textbox character transfer record template
    ; to the dynamic transfer buf.
    ;
    moveq   #4,D3
_anon_z02_35:
    lea     (PeaceTextboxCharTransferRecTemplate).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _anon_z02_35
    ; Load a character from the string and copy it to
    ; the transfer record until we read character $FF.
    ;
    moveq   #0,D3
    move.b  ($0413,A4),D3
    lea     (PeaceText).l,A0
    move.b  (A0,D3.W),D0
    cmpi.b  #$FF,D0
    beq  _L_z02_UpdatePeaceTextbox_AdvanceSubmode
    move.b  D0,($0305,A4)
    ; A regular space takes as much time to emit as any character.
    ; But it makes no sound.
    ;
    cmpi.b  #$24,D0
    beq  _anon_z02_36
    moveq   #16,D0
    move.b  D0,($0604,A4)
_anon_z02_36:
    ; Point to the next character in the string.
    ;
    addq.b  #1,($0413,A4)
    ; Replace the low byte of the VRAM address with the one
    ; where the next character should be written.
    ;
    lea     (PeaceTextboxCharAddrsLo).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0303,A4)
    ; Once the low VRAM address rolls over,
    ; increment the high address.
    ;
    cmpi.b  #$A0,D0
    bcc  _L_z02_UpdatePeaceTextbox_Exit
    moveq   #35,D0
    move.b  D0,($0302,A4)
    even
_L_z02_UpdatePeaceTextbox_Exit:
    rts

