UpdateMode13WinGame_Sub3:
    ; After scrolling 8 pixels, draw another tile row.
    ;
    move.b  ($050B,A4),D0
    cmpi.b  #$08,D0
    bmi  _anon_z02_37
    move.b  ($050B,A4),D0
    move.b  #$08,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$08
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($050B,A4)
    jsr     DrawCredits
_anon_z02_37:
    ; Add $80 to the scroll speed fraction.
    ;
    move.b  ($0058,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$80,D1
    addx.b  D1,D0   ; ADC #$80 (X flag = 6502 C)
    move.b  D0,($0058,A4)
    ; Carry over to the tile offset and current V-scroll.
    ;
    bcc  _anon_z02_38
    addq.b  #1,($050B,A4)
_anon_z02_38:
    move.b  ($00FC,A4),D0
    move.b  #$00,D1
    addx.b  D1,D0   ; ADC #$00 (X flag = 6502 C)
    move.b  D0,($00FC,A4)
    ; If we've reached the bottom of a nametable, then
    ; roll over current V-scroll to 0, and increase number of
    ; screens scrolled.
    ;
    cmpi.b  #$F0,D0
    moveq   #0,D0
    bcs  _anon_z02_39
    move.b  D0,($00FC,A4)
    addq.b  #1,($00E2,A4)
_anon_z02_39:
    ; Roll the carry from the comparison above into bit 0.
    ; So, if reached the bottom of a nametable, switch nametables.
    ;
    roxl.b  #1,D0   ; ROL A
    move.b  D0,($005C,A4)
    ; Put the quest number in Y register.
    ;
    moveq   #0,D3
    moveq   #0,D2
    move.b  ($0016,A4),D2
    lea     ($062D,A4),A0
    move.b  (A0,D2.W),D0
    beq  _anon_z02_40
    addq.b  #1,D3
_anon_z02_40:
    ; If we're not showing the last screen, then return.
    ;
    move.b  ($00E2,A4),D0
    lea     (CreditsLastScreenList).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bcs  _L_z02_UpdateMode13WinGame_Sub3_Exit
    ; If we haven't scrolled the last amount in the last screen,
    ; then return.
    ;
    move.b  ($00FC,A4),D0
    lea     (CreditsLastVscrollList).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bcs  _L_z02_UpdateMode13WinGame_Sub3_Exit
    ; But if we have, then go to the next submode, and set a timer
    ; to wait $40 frames in the next submode.
    ;
    addq.b  #1,($0013,A4)
    moveq   #64,D0
    move.b  D0,($0028,A4)
    even
_L_z02_UpdateMode13WinGame_Sub3_Exit:
    rts

