DrawCredits:
    ; Make a transfer record of a full row of blank tiles.
    ;
    moveq   #31,D3
    moveq   #36,D0
_anon_z02_41:
    lea     ($0305,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _anon_z02_41
    ; No wall tiles go in row 0.
    ;
    move.b  ($050A,A4),D0
    beq  _L_z02_DrawCredits_TerminateRecords
    ; Rows 1 and $2E get horizontal wall tiles.
    ; Rows 2 to $2D get side walls.
    ;
    cmpi.b  #$01,D0
    beq  _L_z02_DrawCredits_WriteHorizontalWalls
    cmpi.b  #$2E,D0
    bcs  _L_z02_DrawCredits_WriteSideWalls
    bne  _L_z02_DrawCredits_TerminateRecords
    even
_L_z02_DrawCredits_WriteHorizontalWalls:
    moveq   #25,D3
    move.b  #$FA,D0
_anon_z02_42:
    lea     ($0308,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _anon_z02_42
    even
_L_z02_DrawCredits_WriteSideWalls:
    move.b  #$FA,D0
    move.b  D0,($0308,A4)
    move.b  D0,($0321,A4)
    even
_L_z02_DrawCredits_TerminateRecords:
    ; Put the buffer's end marker -- whether we transfer tiles and
    ; attributes or only tiles.
    ;
    move.b  #$FF,D0
    move.b  D0,($0325,A4)
    move.b  D0,($0330,A4)
    ; Specify that we're transferring $20 bytes/tiles.
    ;
    moveq   #32,D0
    move.b  D0,($0304,A4)
    ; Write the high byte of the current VRAM page.
    ;
    moveq   #0,D2
    move.b  ($050C,A4),D2
    lea     (CreditLineVramAddrsHi).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0302,A4)
    ; The line number will be used to shift the task mask below.
    ;
    move.b  ($050D,A4),D0
    moveq   #0,D3
    move.b  D0,D3
    ; Multiply the VRAM line number by $20 to get the low VRAM address.
    ;
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    move.b  D0,($0303,A4)
    ; Get the mask for the current VRAM page.
    ;
    lea     (CreditsPagesTextMasks).l,A0
    move.b  (A0,D2.W),D0
_anon_z02_43:
    ; Shift left as many times as the current VRAM line number,
    ; to get the bit that indicates whether this line has text.
    ;
    lsl.b  #1,D0   ; ASL A
    subq.b  #1,D3
    bpl  _anon_z02_43
    bcc  _L_z02_DrawCredits_IncVramLine
    ; The mask inidcates that it should have text.
    ; But if line index >= $17, then it doesn't.
    ;
    moveq   #0,D3
    move.b  ($050E,A4),D3
    cmpi.b  #$17,D3
    bcc  _L_z02_DrawCredits_IncVramLine
    ; In the first quest, don't consider line numbers >= $10.
    ;
    moveq   #0,D2
    move.b  ($0016,A4),D2
    lea     ($062D,A4),A0
    move.b  (A0,D2.W),D0
    bne  _anon_z02_44
    cmpi.b  #$10,D3
    bcc  _L_z02_DrawCredits_IncLine
_anon_z02_44:
    moveq   #0,D2
    move.b  ($0016,A4),D2
    lea     ($062D,A4),A0
    move.b  (A0,D2.W),D0
    ; In the second quest, skip lines $C to $F.
    ;
    beq  _anon_z02_45
    cmpi.b  #$0C,D3
    bcs  _anon_z02_45
    cmpi.b  #$10,D3
    bcs  _L_z02_DrawCredits_IncLine
_anon_z02_45:
    lea     (CreditsTextAddrsLo).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0000,A4)
    lea     (CreditsTextAddrsHi).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0001,A4)
    ; First read the length of the string.
    ;
    moveq   #0,D3
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    move.b  D0,($0002,A4)
    ; Second, read the offset where the first character goes
    ; in the line.
    ;
    addq.b  #1,D3
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    moveq   #0,D2
    move.b  D0,D2
    ; Loop over each character in the rest of the credits source record.
    ;
    addq.b  #1,D3
_anon_z02_46:
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    lea     ($0305,A4),A0
    move.b  D0,(A0,D2.W)
    addq.b  #1,D3
    addq.b  #1,D2
    subq.b  #1,($0002,A4)
    bne  _anon_z02_46
    ; If line index <> $11, go increment.
    ;
    moveq   #0,D3
    move.b  ($050E,A4),D3
    cmpi.b  #$0C,D3
    bcs  _L_z02_DrawCredits_IncLine
    cmpi.b  #$11,D3
    bne  _L_z02_DrawCredits_IncLine
    ; Line index = $11, prepare to read the player's name.
    ;
    move.b  ($0016,A4),D0
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    moveq   #0,D3
    move.b  D0,D3
    ; Copy the player's name at offset 9 in string to transfer.
    ;
    moveq   #0,D2
_anon_z02_47:
    lea     ($0638,A4),A0
    move.b  (A0,D3.W),D0
    lea     ($030E,A4),A0
    move.b  D0,(A0,D2.W)
    addq.b  #1,D3
    addq.b  #1,D2
    cmpi.b  #$08,D2
    bcs  _anon_z02_47
    ; Format the death count for the current save slot.
    ;
    moveq   #0,D3
    move.b  ($0016,A4),D3
    lea     ($0630,A4),A0
    move.b  (A0,D3.W),D0
    jsr     FormatDecimalByte
    ; Copy the decimal death count at offset 19 in string to transfer.
    ;
    moveq   #2,D2
_anon_z02_48:
    move.b  ($01,A4,D2.W),D0
    lea     ($0318,A4),A0
    move.b  D0,(A0,D2.W)
    subq.b  #1,D2
    bpl  _anon_z02_48
    moveq   #0,D3
    move.b  ($050E,A4),D3
    even
_L_z02_DrawCredits_IncLine:
    addq.b  #1,($050E,A4)
    even
_L_z02_DrawCredits_IncVramLine:
    addq.b  #1,($050D,A4)
    ; In each VRAM page there are 8 lines, except in ones where
    ; (page MOD 4) = 3. This means $23xx and $2Bxx.
    ; These pages have 6 lines.
    ;
    move.b  ($050C,A4),D0
    andi.b #$03,D0
    cmpi.b  #$03,D0
    moveq   #8,D0
    bcs  _anon_z02_49
    moveq   #6,D0
_anon_z02_49:
    ; If the VRAM line number has not just been incremented to
    ; the reference line number count, then go write NT attributes.
    ;
    move.b  ($050D,A4),D1
    cmp.b   D1,D0
    bne  _L_z02_DrawCredits_WriteAttributes
    ; Else roll over the VRAM line to 0.
    ;
    moveq   #0,D0
    move.b  D0,($050D,A4)
    ; Increment the VRAM page number.
    ;
    moveq   #0,D3
    move.b  ($050C,A4),D3
    addq.b  #1,D3
    ; If it has reached $C, then roll it over to 0.
    ;
    cmpi.b  #$0C,D3
    bcs  _anon_z02_50
    moveq   #0,D3
    move.b  D0,D3
_anon_z02_50:
    move.b  D3,($050C,A4)
    even
_L_z02_DrawCredits_WriteAttributes:
    ; Every 4 rows, we have to transfer NT attributes.
    ; So, when (counter MOD 4) <> 0, skip filling an attribute record.
    ;
    move.b  ($050A,A4),D0
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z02_DrawCredits_IncRow
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z02_DrawCredits_IncRow
    ; Attributes for the left and right blocks are 0.
    ;
    moveq   #0,D2
    move.b  D2,($0328,A4)
    move.b  D2,($032F,A4)
    ; The row was already divided by 4. So now it refers to an
    ; NT attribute block row. Look up the attribute byte to use
    ; for almost every block in this NT attribute block row.
    ;
    moveq   #0,D3
    move.b  D0,D3
    lea     (CreditsAttrs).l,A0
    move.b  (A0,D3.W),D0
    ; Fill a record with this byte, so the whole NT attribute block
    ; row is changed.
    ;
    moveq   #5,D3
_anon_z02_51:
    lea     ($0329,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _anon_z02_51
    ; If tiles are being written to NT 1 (>= $2800), then
    ; write the high byte of NT 1's attribute space (>= $2BC0).
    ; Else write the high byte of NT 0's attribute space (>= $23C0).
    ;
    moveq   #35,D3
    move.b  ($0302,A4),D0
    andi.b #$08,D0
    beq  _anon_z02_52
    moveq   #43,D3
_anon_z02_52:
    move.b  D3,($0325,A4)
    ; Every attribute block row is at an offset (tile row * 2).
    ;
    move.b  ($050A,A4),D0
    andi.b #$1F,D0
    lsl.b  #1,D0   ; ASL A
    ; Add the offset to the low byte of attribute space base
    ; ($23C0 or $2BC0); and write it to the record.
    ;
    move.b  #$C0,D1
    addx.b  D1,D0   ; ADC #$C0 (X flag = 6502 C)
    move.b  D0,($0326,A4)
    moveq   #8,D0
    move.b  D0,($0327,A4)
    even
_L_z02_DrawCredits_IncRow:
    ; Add 1 to the row.
    ;
    moveq   #0,D3
    move.b  ($050A,A4),D3
    addq.b  #1,D3
    ; Skip the last two rows in each cycle.
    ; When (row MOD $20) gets to $1E, add 2.
    ;
    ; Again, this is because there are
    ; 240 pixels vertically instead of 256.
    ;
    move.b  D3,D0
    andi.b #$1F,D0
    cmpi.b  #$1E,D0
    bcs  _anon_z02_53
    addq.b  #1,D3
    addq.b  #1,D3
_anon_z02_53:
    move.b  D3,($050A,A4)
    rts

    even
WorldFlagBlockAddrs:
    dc.b    $7F, $06, $FF, $06, $7F, $07

    even
SwitchProfileToSecondQuest:
    ; Clear $80 bytes of each block of world flags.
    ;
    moveq   #4,D2
    even
_L_z02_SwitchProfileToSecondQuest_ClearBlock:
    lea     (WorldFlagBlockAddrs).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0000,A4)
    lea     (WorldFlagBlockAddrs+1).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0001,A4)
    moveq   #127,D3
    moveq   #0,D0
_anon_z02_54:
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    subq.b  #1,D3
    bpl  _anon_z02_54
    subq.b  #1,D2
    subq.b  #1,D2
    bpl  _L_z02_SwitchProfileToSecondQuest_ClearBlock
    ; Clear $28 byte block of items.
    ;
    moveq   #39,D3
_anon_z02_55:
    lea     ($0657,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _anon_z02_55
    ; Set 3 full hearts and heart containers.
    ;
    moveq   #34,D0
    move.b  D0,($066F,A4)
    subq.b  #1,($0670,A4)
    moveq   #8,D0
    move.b  D0,($067C,A4)
    moveq   #0,D3
    move.b  ($0016,A4),D3
    moveq   #1,D0
    lea     ($062D,A4),A0
    move.b  D0,(A0,D3.W)
    rts


